import type { NextConfig } from 'next';

const nextConfig: NextConfig = {
  // Static export for Cloudflare Pages
  output: 'export',

  // Trailing slashes for static hosting compatibility
  trailingSlash: true,

  // Disable image optimization for static export
  images: {
    unoptimized: true,
  },

  // TypeScript strict mode
  typescript: {
    // Don't fail build on type errors during development
    // Remove this line for production strictness
    // ignoreBuildErrors: true,
  },

  // ESLint configuration
  eslint: {
    // Don't fail build on lint errors during development
    // ignoreDuringBuilds: true,
  },
};

export default nextConfig;

{
  "compilerOptions": {
    "target": "ES2017",
    "lib": ["dom", "dom.iterable", "esnext"],
    "allowJs": true,
    "skipLibCheck": true,
    "strict": true,
    "noEmit": true,
    "esModuleInterop": true,
    "module": "esnext",
    "moduleResolution": "bundler",
    "resolveJsonModule": true,
    "isolatedModules": true,
    "jsx": "preserve",
    "incremental": true,
    "plugins": [
      {
        "name": "next"
      }
    ],
    "paths": {
      "@/*": ["./src/*"]
    },
    "baseUrl": "."
  },
  "include": ["next-env.d.ts", "**/*.ts", "**/*.tsx", ".next/types/**/*.ts"],
  "exclude": ["node_modules", "public/alpha"]
}

import type { Config } from 'tailwindcss';

const config: Config = {
  darkMode: ['class'],
  content: [
    './src/pages/**/*.{js,ts,jsx,tsx,mdx}',
    './src/components/**/*.{js,ts,jsx,tsx,mdx}',
    './src/app/**/*.{js,ts,jsx,tsx,mdx}',
  ],
  theme: {
    container: {
      center: true,
      padding: {
        DEFAULT: '1rem',
        sm: '1.5rem',
        lg: '2rem',
      },
      screens: {
        sm: '640px',
        md: '768px',
        lg: '1024px',
        xl: '1280px',
        '2xl': '1536px',
      },
    },
    extend: {
      colors: {
        // Full Miami Vice brand palette
        brand: {
          // Neon colors (primary in dark mode)
          pink: '#ff0080',
          'pink-dark': '#cc0066',
          'pink-light': '#ff3399',
          cyan: '#00f0ff',
          'cyan-dark': '#00c0cc',
          'cyan-light': '#33f5ff',
          purple: '#9b59ff',
          'purple-dark': '#7c47cc',
          'purple-light': '#b080ff',
          // Sunset colors (primary in light mode)
          orange: '#ff7033',
          'orange-dark': '#cc5929',
          'orange-light': '#ff8f5c',
          yellow: '#ffbf00',
          'yellow-dark': '#cc9900',
          'yellow-light': '#ffcc33',
          coral: '#ff6b6b',
          'coral-dark': '#cc5656',
          'coral-light': '#ff8989',
        },
        // Semantic colors using CSS variables
        background: 'hsl(var(--background))',
        foreground: 'hsl(var(--foreground))',
        card: {
          DEFAULT: 'hsl(var(--card))',
          foreground: 'hsl(var(--card-foreground))',
        },
        popover: {
          DEFAULT: 'hsl(var(--popover))',
          foreground: 'hsl(var(--popover-foreground))',
        },
        primary: {
          DEFAULT: 'hsl(var(--primary))',
          foreground: 'hsl(var(--primary-foreground))',
        },
        secondary: {
          DEFAULT: 'hsl(var(--secondary))',
          foreground: 'hsl(var(--secondary-foreground))',
        },
        muted: {
          DEFAULT: 'hsl(var(--muted))',
          foreground: 'hsl(var(--muted-foreground))',
        },
        accent: {
          DEFAULT: 'hsl(var(--accent))',
          foreground: 'hsl(var(--accent-foreground))',
        },
        destructive: {
          DEFAULT: 'hsl(var(--destructive))',
          foreground: 'hsl(var(--destructive-foreground))',
        },
        border: 'hsl(var(--border))',
        input: 'hsl(var(--input))',
        ring: 'hsl(var(--ring))',
        chart: {
          '1': 'hsl(var(--chart-1))',
          '2': 'hsl(var(--chart-2))',
          '3': 'hsl(var(--chart-3))',
          '4': 'hsl(var(--chart-4))',
          '5': 'hsl(var(--chart-5))',
        },
      },
      borderRadius: {
        lg: 'var(--radius)',
        md: 'calc(var(--radius) - 2px)',
        sm: 'calc(var(--radius) - 4px)',
      },
      fontFamily: {
        sans: ['var(--font-sans)', 'system-ui', 'sans-serif'],
        mono: ['var(--font-mono)', 'monospace'],
      },
      keyframes: {
        'fade-in': {
          '0%': { opacity: '0' },
          '100%': { opacity: '1' },
        },
        'fade-up': {
          '0%': { opacity: '0', transform: 'translateY(10px)' },
          '100%': { opacity: '1', transform: 'translateY(0)' },
        },
        'slide-in-right': {
          '0%': { transform: 'translateX(100%)' },
          '100%': { transform: 'translateX(0)' },
        },
        'pulse-glow': {
          '0%, 100%': {
            boxShadow: '0 0 20px hsl(var(--brand-primary) / 0.3)',
          },
          '50%': {
            boxShadow: '0 0 40px hsl(var(--brand-primary) / 0.6)',
          },
        },
        shimmer: {
          '0%': { backgroundPosition: '-200% 0' },
          '100%': { backgroundPosition: '200% 0' },
        },
      },
      animation: {
        'fade-in': 'fade-in 0.3s ease-out',
        'fade-up': 'fade-up 0.4s ease-out',
        'slide-in-right': 'slide-in-right 0.3s ease-out',
        'pulse-glow': 'pulse-glow 2s ease-in-out infinite',
        shimmer: 'shimmer 2s linear infinite',
      },
      backgroundImage: {
        // Neon gradients (dark mode favorites)
        'gradient-miami': 'linear-gradient(135deg, #ff0080 0%, #00f0ff 100%)',
        'gradient-neon': 'linear-gradient(135deg, #00f0ff 0%, #ff0080 50%, #9b59ff 100%)',
        // Sunset gradients (light mode favorites)
        'gradient-sunset': 'linear-gradient(135deg, #ff7033 0%, #ff6b6b 50%, #ff0080 100%)',
        'gradient-golden': 'linear-gradient(135deg, #ffbf00 0%, #ff7033 100%)',
        // Universal
        'gradient-rainbow': 'linear-gradient(135deg, #ff0080, #ff7033, #ffbf00, #00f0ff, #9b59ff)',
      },
    },
  },
  plugins: [],
};

export default config;

