@tailwind base;
@tailwind components;
@tailwind utilities;

/**
 * LAZY GOLFING - MIAMI VICE THEME
 * ================================
 * Full Miami Vice color palette with dynamic theme selection.
 * Light theme: Warmer, softer colors (orange, coral, sunset tones)
 * Dark theme: Neon, electric colors (pink, cyan, purple)
 *
 * Brand Colors (Full Palette):
 * - Hot Pink: 330 100% 50% (#ff0080) - Neon pink
 * - Cyan: 184 100% 50% (#00f0ff) - Electric blue
 * - Purple: 270 70% 60% (#9b59ff) - Violet
 * - Orange: 25 100% 55% (#ff7033) - Sunset orange
 * - Yellow: 45 100% 55% (#ffbf00) - Golden yellow
 * - Coral: 10 100% 65% (#ff6b6b) - Warm coral
 */

@layer base {
  :root {
    /* ========== LIGHT THEME (Warmer, Sunset Vibes) ========== */
    --background: 30 30% 98%;
    --foreground: 240 10% 10%;

    --card: 30 20% 99%;
    --card-foreground: 240 10% 10%;

    --popover: 30 20% 99%;
    --popover-foreground: 240 10% 10%;

    /* Primary: Warm coral-orange for light mode */
    --primary: 10 100% 60%;
    --primary-foreground: 0 0% 100%;

    --secondary: 30 15% 94%;
    --secondary-foreground: 240 5.9% 15%;

    --muted: 30 15% 94%;
    --muted-foreground: 240 4% 46%;

    /* Accent: Sunset orange in light mode */
    --accent: 25 100% 55%;
    --accent-foreground: 0 0% 100%;

    --destructive: 0 84% 60%;
    --destructive-foreground: 0 0% 98%;

    --border: 30 15% 88%;
    --input: 30 15% 88%;
    --ring: 25 100% 55%;

    --radius: 0.75rem;

    /* Chart colors - warmer palette for light */
    --chart-1: 25 100% 55%;
    --chart-2: 45 100% 55%;
    --chart-3: 10 100% 65%;
    --chart-4: 330 80% 55%;
    --chart-5: 270 70% 60%;

    /* Full brand palette (always available) */
    --brand-pink: 330 100% 50%;
    --brand-cyan: 184 100% 50%;
    --brand-purple: 270 70% 60%;
    --brand-orange: 25 100% 55%;
    --brand-yellow: 45 100% 55%;
    --brand-coral: 10 100% 65%;

    /* Theme-specific active colors */
    --brand-primary: 25 100% 55%;
    --brand-secondary: 45 100% 55%;
    --brand-accent: 10 100% 65%;
  }

  .dark {
    /* ========== DARK THEME (Neon, Electric Vibes) ========== */
    --background: 240 15% 4%;
    --foreground: 0 0% 98%;

    --card: 240 15% 6%;
    --card-foreground: 0 0% 98%;

    --popover: 240 15% 6%;
    --popover-foreground: 0 0% 98%;

    /* Primary: Hot pink for dark mode (classic Miami Vice) */
    --primary: 330 100% 55%;
    --primary-foreground: 0 0% 100%;

    --secondary: 240 5% 16%;
    --secondary-foreground: 0 0% 98%;

    --muted: 240 5% 16%;
    --muted-foreground: 240 5% 65%;

    /* Accent: Electric cyan in dark mode */
    --accent: 184 100% 50%;
    --accent-foreground: 240 15% 4%;

    --destructive: 0 63% 35%;
    --destructive-foreground: 0 0% 98%;

    --border: 240 5% 18%;
    --input: 240 5% 18%;
    --ring: 330 100% 55%;

    /* Chart colors - neon palette for dark */
    --chart-1: 330 100% 55%;
    --chart-2: 184 100% 55%;
    --chart-3: 270 70% 65%;
    --chart-4: 25 100% 60%;
    --chart-5: 45 100% 60%;

    /* Theme-specific active colors */
    --brand-primary: 330 100% 55%;
    --brand-secondary: 184 100% 50%;
    --brand-accent: 270 70% 60%;
  }
}

@layer base {
  * {
    @apply border-border;
  }
  body {
    @apply bg-background text-foreground;
    font-feature-settings: "rlig" 1, "calt" 1;
  }
}

@layer utilities {
  /**
   * LAZY GOLFING TEXT STYLING SYSTEM
   * ================================
   * Decision: 2025-12-06
   *
   * Rejected: Pink-to-cyan gradient (too generic/basic)
   *
   * Adopted approach:
   * - Neon glow effect for emphasis
   * - Sunset Fade gradient (Orange → Coral → Pink) for hero/primary headings
   * - Golden Hour gradient (Yellow → Orange) for secondary/accent elements
   *
   * Usage guidelines:
   * - .gradient-text-sunset: Main headlines, hero text, brand name
   * - .gradient-text-golden: Taglines, feature highlights, CTAs
   * - .neon-glow: Add to any gradient-text for extra pop (dark mode shines)
   * - .gradient-text: Fallback solid color for simpler contexts
   */

  /* Sunset Fade: Orange → Coral → Pink (primary headlines, hero text) */
  .gradient-text-sunset {
    @apply bg-clip-text text-transparent;
    background-image: linear-gradient(135deg, hsl(var(--brand-orange)) 0%, hsl(var(--brand-coral)) 50%, hsl(var(--brand-pink)) 100%);
  }

  /* Golden Hour: Yellow → Orange (secondary elements, taglines, CTAs) */
  .gradient-text-golden {
    @apply bg-clip-text text-transparent;
    background-image: linear-gradient(135deg, hsl(var(--brand-yellow)) 0%, hsl(var(--brand-orange)) 100%);
  }

  /* Solid fallback - theme-adaptive primary color */
  .gradient-text {
    color: hsl(var(--brand-primary));
  }

  /* Alternative solid (uses accent) */
  .gradient-text-alt {
    color: hsl(var(--brand-accent));
  }

  /* Neon glow effects - adds depth and pop, especially in dark mode */
  .neon-glow {
    text-shadow:
      0 0 10px hsl(var(--brand-primary) / 0.5),
      0 0 20px hsl(var(--brand-primary) / 0.3),
      0 0 40px hsl(var(--brand-primary) / 0.2);
  }

  .neon-glow-warm {
    text-shadow:
      0 0 10px hsl(var(--brand-orange) / 0.5),
      0 0 20px hsl(var(--brand-coral) / 0.3),
      0 0 40px hsl(var(--brand-pink) / 0.2);
  }

  .neon-glow-golden {
    text-shadow:
      0 0 10px hsl(var(--brand-yellow) / 0.5),
      0 0 20px hsl(var(--brand-orange) / 0.3),
      0 0 40px hsl(var(--brand-orange) / 0.2);
  }

  .neon-glow-secondary {
    text-shadow:
      0 0 10px hsl(var(--brand-secondary) / 0.5),
      0 0 20px hsl(var(--brand-secondary) / 0.3),
      0 0 40px hsl(var(--brand-secondary) / 0.2);
  }

  /* Glass morphism */
  .glass {
    @apply backdrop-blur-md border border-border/50;
    background: hsl(var(--card) / 0.8);
  }

  .glass-strong {
    @apply backdrop-blur-lg border border-border/30;
    background: hsl(var(--card) / 0.9);
  }

  /* Background glows - theme adaptive */
  .bg-glow-primary {
    background: radial-gradient(ellipse 80% 50% at 50% -20%, hsl(var(--brand-primary) / 0.15), transparent);
  }

  .bg-glow-secondary {
    background: radial-gradient(ellipse 80% 50% at 50% 120%, hsl(var(--brand-secondary) / 0.1), transparent);
  }

  .bg-glow-mixed {
    background:
      radial-gradient(ellipse 60% 40% at 10% 0%, hsl(var(--brand-primary) / 0.12), transparent),
      radial-gradient(ellipse 60% 40% at 90% 100%, hsl(var(--brand-secondary) / 0.12), transparent);
  }

  .bg-glow-sunset {
    background:
      radial-gradient(ellipse 50% 30% at 0% 0%, hsl(var(--brand-orange) / 0.15), transparent),
      radial-gradient(ellipse 50% 30% at 100% 0%, hsl(var(--brand-yellow) / 0.12), transparent),
      radial-gradient(ellipse 60% 40% at 50% 100%, hsl(var(--brand-coral) / 0.1), transparent);
  }

  .bg-glow-neon {
    background:
      radial-gradient(ellipse 50% 30% at 0% 0%, hsl(var(--brand-pink) / 0.15), transparent),
      radial-gradient(ellipse 50% 30% at 100% 0%, hsl(var(--brand-cyan) / 0.12), transparent),
      radial-gradient(ellipse 60% 40% at 50% 100%, hsl(var(--brand-purple) / 0.1), transparent);
  }

  /* Custom scrollbar */
  .scrollbar-thin {
    scrollbar-width: thin;
    scrollbar-color: hsl(var(--muted)) transparent;
  }

  .scrollbar-thin::-webkit-scrollbar {
    width: 8px;
    height: 8px;
  }

  .scrollbar-thin::-webkit-scrollbar-track {
    background: transparent;
  }

  .scrollbar-thin::-webkit-scrollbar-thumb {
    background-color: hsl(var(--muted));
    border-radius: 4px;
  }

  /* Gradient borders */
  .gradient-border {
    position: relative;
    background: hsl(var(--card));
    border-radius: var(--radius);
  }

  .gradient-border::before {
    content: '';
    position: absolute;
    inset: -1px;
    border-radius: calc(var(--radius) + 1px);
    padding: 1px;
    background: hsl(var(--brand-primary));
    -webkit-mask: linear-gradient(#fff 0 0) content-box, linear-gradient(#fff 0 0);
    mask: linear-gradient(#fff 0 0) content-box, linear-gradient(#fff 0 0);
    -webkit-mask-composite: xor;
    mask-composite: exclude;
  }

  /* Container utilities */
  .container-full {
    @apply w-full max-w-none px-4 sm:px-6 lg:px-8;
  }

  .container-wide {
    @apply w-full max-w-7xl mx-auto px-4 sm:px-6 lg:px-8;
  }

  .container-xl {
    @apply w-full max-w-[1400px] mx-auto px-4 sm:px-6 lg:px-8;
  }

  .container-2xl {
    @apply w-full max-w-[1800px] mx-auto px-4 sm:px-6 lg:px-8;
  }
}

'use client';

import Link from 'next/link';
import Image from 'next/image';
import { usePathname } from 'next/navigation';
import { ThemeToggle } from '@/components/theme-toggle';
import { Button } from '@/components/ui/button';
import { cn } from '@/lib/utils';

const navLinks = [
