/**
 * JSON-LD Component for Schema.org Structured Data
 *
 * Use this component to add structured data to pages for better SEO.
 * Schema.org markup helps search engines understand page content
 * and can result in rich snippets in search results.
 *
 * Security Note: This uses JSON.stringify which safely escapes all content.
 * The data passed to this component should always be from trusted sources
 * (our own code/database), never from raw user input.
 *
 * @example
 * // In a page or layout:
 * <JsonLd data={websiteSchema} />
 * <JsonLd data={organizationSchema} />
 */

import Script from 'next/script';

interface JsonLdProps {
  data: Record<string, unknown>;
}

export function JsonLd({ data }: JsonLdProps) {
  // JSON.stringify escapes content, making this safe for trusted data
  const jsonString = JSON.stringify(data);

  return (
    <Script
      id={`json-ld-${data['@type'] || 'schema'}`}
      type="application/ld+json"
      strategy="afterInteractive"
    >
      {jsonString}
    </Script>
  );
}

/**
 * Pre-built Schema.org objects for Lazy Golfing
 * Import these directly or use as templates for custom schemas
 */

export const websiteSchema = {
  '@context': 'https://schema.org',
  '@type': 'WebSite',
  name: 'Lazy Golfing',
  url: 'https://lazygolfing.com',
  description: 'The comprehensive golf tracking platform for rounds, leagues, tournaments, and more.',
  potentialAction: {
    '@type': 'SearchAction',
    target: {
      '@type': 'EntryPoint',
      urlTemplate: 'https://lazygolfing.com/search?q={search_term_string}',
    },
    'query-input': 'required name=search_term_string',
  },
};

export const organizationSchema = {
  '@context': 'https://schema.org',
  '@type': 'Organization',
  name: 'Lazy Golfing',
  url: 'https://lazygolfing.com',
  logo: 'https://lazygolfing.com/images/logo.png',
  sameAs: [
    // Add social media URLs when available
    // 'https://twitter.com/lazygolfing',
    // 'https://facebook.com/lazygolfing',
  ],
  contactPoint: {
    '@type': 'ContactPoint',
    contactType: 'customer service',
    url: 'https://lazygolfing.com/contact',
  },
};

export const sportsOrganizationSchema = {
  '@context': 'https://schema.org',
  '@type': 'SportsOrganization',
  name: 'Lazy Golfing',
  url: 'https://lazygolfing.com',
  sport: 'Golf',
  description: 'Golf tracking platform for recreational golfers, leagues, and tournaments.',
};

/**
 * Factory functions for dynamic Schema.org objects
 */

export function createBreadcrumbSchema(items: { name: string; url: string }[]) {
  return {
    '@context': 'https://schema.org',
    '@type': 'BreadcrumbList',
    itemListElement: items.map((item, index) => ({
      '@type': 'ListItem',
      position: index + 1,
      name: item.name,
      item: item.url,
    })),
  };
}

export function createSportsEventSchema(options: {
  name: string;
  startDate: string;
  endDate?: string;
  location?: string;
  description?: string;
  url?: string;
}) {
  return {
    '@context': 'https://schema.org',
    '@type': 'SportsEvent',
    name: options.name,
    startDate: options.startDate,
    endDate: options.endDate,
    location: options.location
      ? {
          '@type': 'Place',
          name: options.location,
        }
      : undefined,
    description: options.description,
    url: options.url,
    sport: 'Golf',
  };
}

export function createGolfCourseSchema(options: {
  name: string;
  address: {
    streetAddress: string;
    addressLocality: string;
    addressRegion: string;
    postalCode: string;
    addressCountry: string;
  };
  telephone?: string;
  url?: string;
  geo?: { latitude: number; longitude: number };
}) {
  return {
    '@context': 'https://schema.org',
    '@type': 'GolfCourse',
    name: options.name,
    address: {
      '@type': 'PostalAddress',
      ...options.address,
    },
    telephone: options.telephone,
    url: options.url,
