/**
 * Lazy Golfing - API Configuration
 *
 * Centralized API configuration for the Next.js frontend.
 * Automatically detects development vs production environments.
 */

// API base URL - uses environment variable or defaults based on hostname
export const API_BASE =
  process.env.NEXT_PUBLIC_API_URL ||
  (typeof window !== 'undefined' &&
  (window.location.hostname === 'localhost' ||
    window.location.hostname === '127.0.0.1')
    ? 'http://localhost:3000'
    : 'https://api.lazygolfing.com');

// Check if running in development mode
export const IS_DEV =
  typeof window !== 'undefined' &&
  (window.location.hostname === 'localhost' ||
    window.location.hostname === '127.0.0.1');

/**
 * Get CSRF token from cookies
 */
function getCsrfToken(): string | null {
  if (typeof document === 'undefined') return null;
  const match = document.cookie.match(/csrf_token=([^;]+)/);
  return match ? match[1] : null;
}

/**
 * API response wrapper
 */
interface ApiResponse<T> {
  ok: boolean;
  status: number;
  data: T | null;
}

/**
 * Make an API request with consistent configuration
 *
 * @param path - API endpoint path (e.g., '/v1/me')
 * @param options - Fetch options (method, body, headers, etc.)
 * @returns Promise with response data
 */
export async function apiRequest<T = unknown>(
  path: string,
  options: RequestInit = {}
): Promise<ApiResponse<T>> {
  const method = (options.method || 'GET').toUpperCase();

  const headers: Record<string, string> = {
    'Content-Type': 'application/json',
    ...(options.headers as Record<string, string>),
  };

  // Add CSRF token for state-changing requests
  if (['POST', 'PUT', 'PATCH', 'DELETE'].includes(method)) {
    const csrfToken = getCsrfToken();
    if (csrfToken) {
      headers['X-CSRF-Token'] = csrfToken;
    }
  }

  const res = await fetch(`${API_BASE}${path}`, {
    method,
    credentials: 'include', // Include cookies for JWT
    headers,
    ...options,
  });

  // Handle 204 No Content
  if (res.status === 204) {
    return { ok: true, status: 204, data: null };
  }

  // Parse response based on content type
  const contentType = res.headers.get('content-type') || '';
  let data: T | null = null;

  if (contentType.includes('application/json')) {
    try {
      data = await res.json();
    } catch {
      // JSON parse failed
    }
  } else {
    try {
      data = (await res.text()) as unknown as T;
    } catch {
      // Text parse failed
    }
  }

  return { ok: res.ok, status: res.status, data };
}

