/**
 * Lazy Golfing - Authentication Utilities
 *
 * Handles Google OAuth flow and session management.
 * Uses HttpOnly JWT cookies managed by the backend.
 */

import { API_BASE, apiRequest } from './api';

/**
 * User session response from /auth/session
 */
export interface Session {
  authenticated: boolean;
  user?: {
    id: string;
    email: string;
    name?: string;
  };
}

/**
 * User profile from /v1/me
 */
export interface UserProfile {
  id: string;
  email: string;
  firstName?: string;
  lastName?: string;
  displayName?: string;
  handicap?: number;
  ghin?: string;
  avatarUrl?: string;
  createdAt: string;
  updatedAt: string;
}

/**
 * Check if user is authenticated
 * @returns Session object with authentication status
 */
export async function getSession(): Promise<Session> {
  const { ok, data } = await apiRequest<Session>('/auth/session');
  return ok && data ? data : { authenticated: false };
}

/**
 * Get current user's profile
 * @returns User profile or null if not authenticated
 */
export async function getMe(): Promise<UserProfile | null> {
  const { ok, status, data } = await apiRequest<UserProfile>('/v1/me');
  if (ok && data) return data;
  if (status === 401) return null;
  throw new Error('Failed to fetch user profile');
}

/**
 * Update current user's profile
 * @param payload - Profile fields to update
 * @returns Updated profile or null if not authenticated
 */
export async function updateMe(
  payload: Partial<UserProfile>
): Promise<UserProfile | null> {
  const { ok, status, data } = await apiRequest<UserProfile>('/v1/me', {
    method: 'PUT',
    body: JSON.stringify(payload),
  });
  if (ok && data) return data;
  if (status === 401) return null;
  throw new Error('Failed to update profile');
}

/**
 * Log out the current user
 * Clears the JWT cookie on the server
 */
export async function logout(): Promise<void> {
  await apiRequest('/auth/logout', { method: 'POST' });
}

/**
 * Redirect to Google OAuth login
 * Initiates the OAuth flow via the backend
 */
export function redirectToGoogleLogin(): void {
  window.location.href = `${API_BASE}/auth/google`;
}

/**
 * Get the Google OAuth URL (without redirecting)
 * Useful for rendering login buttons
 */
export function getGoogleLoginUrl(): string {
  return `${API_BASE}/auth/google`;
}

