import * as React from 'react';
import { Slot } from '@radix-ui/react-slot';
import { cva, type VariantProps } from 'class-variance-authority';
import { cn } from '@/lib/utils';

const buttonVariants = cva(
  'inline-flex items-center justify-center gap-2 whitespace-nowrap rounded-md text-sm font-medium transition-colors focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring disabled:pointer-events-none disabled:opacity-50 [&_svg]:pointer-events-none [&_svg]:size-4 [&_svg]:shrink-0',
  {
    variants: {
      variant: {
        default:
          'bg-primary text-primary-foreground shadow hover:bg-primary/90',
        destructive:
          'bg-destructive text-destructive-foreground shadow-sm hover:bg-destructive/90',
        outline:
          'border border-input bg-background shadow-sm hover:bg-accent hover:text-accent-foreground',
        secondary:
          'bg-secondary text-secondary-foreground shadow-sm hover:bg-secondary/80',
        ghost: 'hover:bg-accent hover:text-accent-foreground',
        link: 'text-primary underline-offset-4 hover:underline',
      },
      size: {
        default: 'h-9 px-4 py-2',
        sm: 'h-8 rounded-md px-3 text-xs',
        lg: 'h-10 rounded-md px-8',
        icon: 'h-9 w-9',
      },
    },
    defaultVariants: {
      variant: 'default',
      size: 'default',
    },
  }
);

export interface ButtonProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement>,
    VariantProps<typeof buttonVariants> {
  asChild?: boolean;
}

const Button = React.forwardRef<HTMLButtonElement, ButtonProps>(
  ({ className, variant, size, asChild = false, ...props }, ref) => {
    const Comp = asChild ? Slot : 'button';
    return (
      <Comp
        className={cn(buttonVariants({ variant, size, className }))}
        ref={ref}
        {...props}
      />
    );
  }
);
Button.displayName = 'Button';

export { Button, buttonVariants };

'use client';

import { useEffect, useState } from 'react';
import Link from 'next/link';
import Image from 'next/image';
import { Button } from '@/components/ui/button';
import { getSession, getGoogleLoginUrl } from '@/lib/auth';

export default function LoginPage() {
  const [isChecking, setIsChecking] = useState(true);
  const [isAuthenticated, setIsAuthenticated] = useState(false);

  useEffect(() => {
    // Check if user is already logged in
    getSession()
      .then((session) => {
        if (session.authenticated) {
          setIsAuthenticated(true);
          // Redirect to profile after a brief moment
          setTimeout(() => {
            window.location.href = '/profile';
          }, 1500);
        }
      })
      .catch(() => {
        // Ignore errors, show login
      })
      .finally(() => {
        setIsChecking(false);
      });
  }, []);

  return (
    <div className="relative w-full overflow-hidden">
      {/* Background effects */}
      <div className="absolute inset-0 -z-10 bg-glow-mixed" />

      <div className="w-full max-w-md mx-auto px-4 py-16">
        <div className="glass rounded-2xl p-8 text-center space-y-8">
          {/* Logo */}
          <div className="flex justify-center">
            <Image
              src="/images/logo.png"
              alt="Lazy Golfing"
              width={200}
              height={148}
              className="h-24 w-auto"
            />
          </div>

          {/* Title */}
          <div className="space-y-2">
            <h1 className="text-2xl font-bold">Welcome Back</h1>
            <p className="text-muted-foreground">
              Sign in to track your rounds and improve your game
            </p>
          </div>

          {/* Status */}
          {isChecking ? (
            <div className="py-4">
              <div className="animate-pulse text-muted-foreground">
                Checking session...
              </div>
            </div>
          ) : isAuthenticated ? (
            <div className="py-4 space-y-2">
              <div className="text-brand-pink font-semibold">
                You&apos;re already logged in!
              </div>
              <div className="text-muted-foreground text-sm">
                Redirecting to your profile...
              </div>
            </div>
          ) : (
            <>
              {/* Google Sign In Button */}
              <Button
                size="lg"
                className="w-full text-base gap-3"
                onClick={() => {
                  window.location.href = getGoogleLoginUrl();
                }}
              >
                <svg className="w-5 h-5" viewBox="0 0 24 24">
                  <path
                    fill="currentColor"
                    d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z"
                  />
                  <path
                    fill="currentColor"
                    d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z"
                  />
                  <path
                    fill="currentColor"
                    d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z"
                  />
                  <path
                    fill="currentColor"
                    d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z"
                  />
                </svg>
                Sign in with Google
              </Button>

              {/* Tagline */}
              <p className="text-sm gradient-text-golden italic">
                Cart golf only!
              </p>
            </>
          )}

          {/* Back to home */}
          <div className="pt-4 border-t border-border/50">
            <Link
              href="/"
              className="text-sm text-muted-foreground hover:text-foreground transition-colors"
            >
              &larr; Back to home
            </Link>
          </div>
        </div>
      </div>
    </div>
  );
}

import Link from 'next/link';
import Image from 'next/image';
import { ThemeToggle } from '@/components/theme-toggle';

/**
 * Auth Layout
 *
 * Minimal layout for authentication pages (login, signup, forgot password, etc.)
 * Uses a simplified header without full navigation and a minimal footer.
 * This is a Next.js Route Group - the (auth) folder name doesn't appear in URLs.
 */
export default function AuthLayout({
  children,
}: {
  children: React.ReactNode;
}) {
  return (
    <div className="min-h-screen flex flex-col">
      {/* Minimal Header */}
      <header className="sticky top-0 z-50 w-full border-b border-border/40 bg-background/95 backdrop-blur supports-[backdrop-filter]:bg-background/60">
        <div className="w-full max-w-[1800px] mx-auto flex h-20 items-center justify-between px-4 sm:px-6 lg:px-8">
          <Link href="/" className="flex items-center gap-3">
            <Image
              src="/images/logo.png"
              alt="Lazy Golfing"
              width={162}
              height={120}
              className="h-14 sm:h-16 w-auto"
              priority
            />
            <span className="text-xl sm:text-2xl font-bold gradient-text-sunset neon-glow-warm hidden sm:inline">
              Lazy Golfing
            </span>
          </Link>
          <ThemeToggle />
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 flex items-center justify-center">
        {children}
      </main>

      {/* Minimal Footer */}
      <footer className="w-full border-t border-border/40 bg-muted/20 py-6">
        <div className="text-center text-sm text-muted-foreground">
          &copy; {new Date().getFullYear()} Lazy Golfing. All rights reserved.
        </div>
      </footer>
    </div>
  );
}

